	public void deletePdfFile(String pdfFile)
	{
		String function_nm="deletePdfFile()";
		try
		{
			File file = new File(pdfFile);
			if(file.exists())
			{
				boolean delete = file.delete();
			}
		}
		catch(Exception e)
		{
			new SystemErrorLogger().InsertErrorLogger(db_src_file_name, function_nm, e);
			throw e;
		}
		
	}

